+    topicNext: "next action",
+    topicScore: "last score",
+    topicBlock: "blocking",
+    files: "project files",
+    yes: "yes",
+    no: "no"
+  },
+  en: {
+    eyebrow: "project operating board",
+    title: "pgg dashboard",
+    empty: "No registered projects. Run `pgg init` or `pgg dashboard --snapshot-only` first.",
+    loading: "Loading dashboard snapshot...",
+    projects: "Projects",
+    overview: "Overview",
+    topics: "Topics",
+    workflow: "Workflow",
+    settings: "Settings",
+    registered: "registered",
+    current: "current",
+    active: "active",
+    archive: "archive",
+    language: "language",
+    autoMode: "auto mode",
+    provider: "provider",
+    version: "version",
+    health: "health",
+    path: "path",
+    missing: "missing root",
+    partial: "partial",
+    ok: "ok",
+    noWorkflow: "No workflow data exists for the selected topic.",
+    noTopics: "No topics match the active filter.",
+    searchPlaceholder: "Search topics",
+    generatedAt: "generated",
+    commands: "recommended commands",
+    topicNext: "next action",
+    topicScore: "last score",
+    topicBlock: "blocking",
+    files: "project files",
+    yes: "yes",
+    no: "no"
+  }
+} as const;
+
+function App() {
+  const selectedProjectId = useDashboardStore((state) => state.selectedProjectId);
+  const selectedTopicKey = useDashboardStore((state) => state.selectedTopicKey);
+  const topicFilter = useDashboardStore((state) => state.topicFilter);
+  const setSelectedProjectId = useDashboardStore((state) => state.setSelectedProjectId);
+  const setSelectedTopicKey = useDashboardStore((state) => state.setSelectedTopicKey);
+  const setTopicFilter = useDashboardStore((state) => state.setTopicFilter);
+  const deferredFilter = useDeferredValue(topicFilter);
+
+  const snapshotQuery = useQuery({
+    queryKey: ["dashboard-snapshot"],
+    queryFn: async (): Promise<DashboardSnapshot> => {
+      const response = await fetch(`/dashboard-data.json?ts=${Date.now()}`);
+      if (!response.ok) {
+        throw new Error("Failed to load dashboard snapshot.");
+      }
+
+      return (await response.json()) as DashboardSnapshot;
+    },
+    staleTime: Infinity
+  });
+
+  const snapshot = snapshotQuery.data;
+  const fallbackProject =
+    snapshot?.projects.find((project) => project.id === snapshot.currentProjectId) ??
+    snapshot?.projects[0] ??
+    null;
+  const selectedProject =
+    snapshot?.projects.find((project) => project.id === selectedProjectId) ?? fallbackProject;
+  const dictionary = copy[selectedProject?.language ?? "en"];
+
+  useEffect(() => {
+    if (!snapshot?.projects.length) {
+      return;
+    }
+
+    if (!selectedProjectId) {
+      const nextProjectId = snapshot.currentProjectId ?? snapshot.projects[0]?.id ?? null;
+      startTransition(() => {
+        setSelectedProjectId(nextProjectId);
+      });
+    }
+  }, [selectedProjectId, setSelectedProjectId, snapshot]);
+
+  const allTopics = selectedProject
+    ? [...selectedProject.activeTopics, ...selectedProject.archivedTopics]
+    : [];
+  const visibleTopics = allTopics.filter((topic) => {
+    if (!deferredFilter.trim()) {
+      return true;
+    }
+
+    return `${topic.name} ${topic.stage ?? ""} ${topic.goal ?? ""}`
+      .toLowerCase()
+      .includes(deferredFilter.toLowerCase());
+  });
+  const selectedTopic =
+    visibleTopics.find((topic) => `${topic.bucket}:${topic.name}` === selectedTopicKey) ??
+    visibleTopics[0] ??
+    null;
+
+  useEffect(() => {
+    if (!visibleTopics.length) {
+      return;
+    }
+
+    if (!selectedTopicKey || !visibleTopics.some((topic) => `${topic.bucket}:${topic.name}` === selectedTopicKey)) {
+      startTransition(() => {
+        setSelectedTopicKey(`${visibleTopics[0]!.bucket}:${visibleTopics[0]!.name}`);
+      });
+    }
+  }, [selectedTopicKey, setSelectedTopicKey, visibleTopics]);
+
+  if (snapshotQuery.isLoading) {
+    return <main className="app-shell empty-state">{dictionary.loading}</main>;
+  }
+
+  if (!snapshot || snapshot.projects.length === 0) {
+    return <main className="app-shell empty-state">{dictionary.empty}</main>;
+  }
+
+  return (
+    <main className="app-shell">
+      <section className="hero">
+        <div>
+          <p className="eyebrow">{dictionary.eyebrow}</p>
+          <h1>{dictionary.title}</h1>
+        </div>
+        <div className="hero-meta">
+          <span>{dictionary.generatedAt}</span>
+          <strong>{new Date(snapshot.generatedAt).toLocaleString()}</strong>
+        </div>
+      </section>
+
+      <section className="layout">
+        <aside className="panel project-panel">
+          <div className="panel-header">
+            <h2>{dictionary.projects}</h2>
+          </div>
+          <div className="project-list">
+            {snapshot.projects.map((project) => {
+              const isSelected = project.id === selectedProject?.id;
+              return (
+                <button
+                  key={project.id}
+                  className={`project-card${isSelected ? " selected" : ""}`}
+                  onClick={() => {
+                    startTransition(() => {
+                      setSelectedProjectId(project.id);
+                      setSelectedTopicKey(null);
+                    });
+                  }}
+                  type="button"
+                >
+                  <span className="project-chip">{project.registered ? dictionary.registered : dictionary.current}</span>
+                  <strong>{project.name}</strong>
+                  <span>{project.rootDir}</span>
+                  <div className="project-flags">
+                    <span>{project.language}</span>
+                    <span>{project.autoMode}</span>
+                    <span>{project.provider}</span>
+                  </div>
+                </button>
+              );
+            })}
+          </div>
+        </aside>
+
+        <section className="main-grid">
+          <article className="panel overview-panel">
+            <div className="panel-header">
+              <h2>{dictionary.overview}</h2>
+            </div>
+            {selectedProject ? (
+              <div className="overview-grid">
+                <div className="metric-card accent">
+                  <span>{dictionary.active}</span>
+                  <strong>{selectedProject.activeTopics.length}</strong>
+                </div>
+                <div className="metric-card">
+                  <span>{dictionary.archive}</span>
+                  <strong>{selectedProject.archivedTopics.length}</strong>
+                </div>
+                <div className="metric-card">
+                  <span>{dictionary.health}</span>
+                  <strong>{selectedProject.missingRoot ? dictionary.missing : dictionary.ok}</strong>
+                </div>
+                <div className="detail-card">
+                  <span>{dictionary.path}</span>
+                  <strong>{selectedProject.rootDir}</strong>
+                </div>
+                <div className="detail-card">
+                  <span>{dictionary.provider}</span>
+                  <strong>{selectedProject.provider}</strong>
+                </div>
+                <div className="detail-card">
+                  <span>{dictionary.version}</span>
+                  <strong>{selectedProject.installedVersion ?? "n/a"}</strong>
+                </div>
+                <div className="detail-card">
+                  <span>{dictionary.files}</span>
+                  <strong>
+                    AGENTS {selectedProject.hasAgents ? dictionary.yes : dictionary.no} / .codex{" "}
+                    {selectedProject.hasCodex ? dictionary.yes : dictionary.no} / poggn{" "}
+                    {selectedProject.hasPoggn ? dictionary.yes : dictionary.no}
+                  </strong>
+                </div>
+              </div>
+            ) : null}
+          </article>
+
+          <article className="panel topics-panel">
+            <div className="panel-header">
+              <h2>{dictionary.topics}</h2>
+              <input
+                className="topic-search"
+                onChange={(event) => setTopicFilter(event.target.value)}
+                placeholder={dictionary.searchPlaceholder}
+                value={topicFilter}
+              />
+            </div>
+            <div className="topic-list">
+              {visibleTopics.length === 0 ? (
+                <div className="empty-hint">{dictionary.noTopics}</div>
+              ) : (
+                visibleTopics.map((topic) => {
+                  const key = `${topic.bucket}:${topic.name}`;
+                  const selected = key === selectedTopicKey;
+                  return (
+                    <button
+                      key={key}
+                      className={`topic-card${selected ? " selected" : ""}`}
+                      onClick={() => {
+                        startTransition(() => {
+                          setSelectedTopicKey(key);
+                        });
+                      }}
+                      type="button"
+                    >
+                      <div className="topic-card-top">
+                        <strong>{topic.name}</strong>
+                        <span className={`badge ${topic.bucket}`}>{topic.bucket}</span>
+                      </div>
+                      <span>{topic.stage ?? "-"}</span>
+                      <p>{topic.goal ?? "-"}</p>
+                      <div className="topic-meta">
+                        <span>
+                          {dictionary.topicScore}: {topic.score ?? "-"}
+                        </span>
+                        <span>{topic.health === "ok" ? dictionary.ok : dictionary.partial}</span>
+                      </div>
+                    </button>
+                  );
+                })
+              )}
+            </div>
+          </article>
+
+          <article className="panel workflow-panel">
+            <div className="panel-header">
+              <h2>{dictionary.workflow}</h2>
+            </div>
+            {selectedTopic?.workflow ? (
+              <div className="workflow-canvas">
+                <ReactFlow
+                  fitView
+                  nodes={selectedTopic.workflow.nodes}
+                  edges={selectedTopic.workflow.edges}
+                  nodesDraggable={false}
+                  panOnDrag
+                >
+                  <MiniMap />
+                  <Controls />
+                  <Background />
+                </ReactFlow>
+              </div>
+            ) : (
+              <div className="empty-hint">{dictionary.noWorkflow}</div>
+            )}
+          </article>
+
+          <article className="panel settings-panel">
+            <div className="panel-header">
+              <h2>{dictionary.settings}</h2>
+            </div>
+            {selectedProject ? (
+              <div className="settings-stack">
+                <div className="setting-item">
+                  <span>{dictionary.language}</span>
+                  <strong>{selectedProject.language}</strong>
+                  <code>pgg lang --cwd "{selectedProject.rootDir}"</code>
+                </div>
+                <div className="setting-item">
+                  <span>{dictionary.autoMode}</span>
+                  <strong>{selectedProject.autoMode}</strong>
+                  <code>pgg auto --cwd "{selectedProject.rootDir}"</code>
+                </div>
+                <div className="setting-item">
+                  <span>{dictionary.commands}</span>
+                  <code>pgg update --cwd "{selectedProject.rootDir}"</code>
+                </div>
+                {selectedTopic ? (
+                  <div className="setting-item topic-callout">
+                    <span>{dictionary.topicNext}</span>
+                    <strong>{selectedTopic.nextAction ?? "-"}</strong>
+                    <span>
+                      {dictionary.topicBlock}: {selectedTopic.blockingIssues ?? "-"}
+                    </span>
+                  </div>
+                ) : null}
+              </div>
+            ) : null}
+          </article>
+        </section>
+      </section>
+    </main>
+  );
+}
+
+export default App;

