+function buildTopicStatusSummary(
+  topic: TopicSummary,
+  currentStage: TopicStageName | null,
+  nextWorkflow: TopicNextWorkflow,
+  reason: string,
+  progressStatus: TopicProgressStatus
+): TopicStatusSummary {
